<?php $labels=['pending_whatsapp'=>'Baru','confirmed'=>'Dikonfirmasi','completed'=>'Selesai','cancelled'=>'Dibatalkan'];?><header class="page-head"><div><span class="eyebrow">Penjualan</span><h1>Pesanan WhatsApp</h1></div></header><section class="panel"><p class="panel-help">Konfirmasi pesanan setelah pelanggan menyetujui pembelian. Status Dikonfirmasi akan mengurangi stok.</p><div class="table-wrap" tabindex="0" aria-label="Daftar pesanan, geser horizontal bila diperlukan"><table><thead><tr><th>Nomor</th><th>Pelanggan</th><th>Total</th><th>Dibuat</th><th>Status</th></tr></thead><tbody><?php foreach($items as $x):?><tr><td><strong><?=e($x['order_number'])?></strong></td><td><?=e($x['customer_name'])?><small><?=e($x['customer_phone'])?></small></td><td><?=money($x['grand_total'])?></td><td><?=e($x['created_at'])?></td><td><form class="inline-form" method="post" action="<?=url('/admin/orders/'.$x['id'])?>" onsubmit="return confirm('Ubah status pesanan? Perubahan dapat memengaruhi stok.')"><?=csrf_field()?><input type="hidden" name="_method" value="PUT"><label><span class="sr-only">Status <?=e($x['order_number'])?></span><select name="status"><?php foreach($labels as $value=>$label):?><option value="<?=$value?>" <?=$x['status']===$value?'selected':''?>><?=$label?></option><?php endforeach?></select></label><button>Simpan status</button></form></td></tr><?php endforeach?><?php if(!$items):?><tr><td colspan="5" class="empty-cell">Belum ada pesanan. Pesanan checkout WhatsApp akan muncul di sini.</td></tr><?php endif?></tbody></table></div></section>
